/**
 * Validate Crypto ML-DSA key Retrieving (from PEM & X509) & signature Interfaces.
 *
 * @retval  true   Validation succeeded.
 * @retval  false  Validation failed.
 **/
bool libspdm_validate_crypt_mldsa_2(void)
{
    bool status;
    void *mldsa_priv_key;
    void *mldsa_pub_key;
    uint8_t message[] = "MlDsaTest";
    uint8_t context[] = "MlDsaContext";
    uint8_t signature[4627];
    size_t sig_size;

    libspdm_my_print("\nCrypto ML-DSA key Retrieving Testing: ");

    /* Retrieve ML-DSA private key from PEM data. */
    libspdm_my_print("\n- Retrieve ML-DSA Private key from PEM ...");
    status = libspdm_mldsa_get_private_key_from_pem(m_libspdm_mldsa_test_pem_key,
                                                    sizeof(m_libspdm_mldsa_test_pem_key),
                                                    NULL, &mldsa_priv_key);
    if (!status) {
        libspdm_my_print("[Fail]");
        return false;
    } else {
        libspdm_my_print("[Pass]");
    }

    /* Sign ML-DSA */
    sig_size = sizeof(signature);
    libspdm_my_print("\n- ML-DSA Signing ... ");
    status = libspdm_mldsa_sign(mldsa_priv_key, context, sizeof(context),
                                message, sizeof(message),
                                signature, &sig_size);
    if (!status) {
        libspdm_my_print("[Fail]");
        libspdm_mldsa_free(mldsa_priv_key);
        return false;
    } else {
        libspdm_my_print("[Pass]");
    }

    /* Retrieve ML-DSA Public key from DER data. */
    libspdm_my_print("\n- Retrieve ML-DSA Public key from DER ...");
    status = libspdm_mldsa_get_public_key_from_der(m_libspdm_mldsa_test_pub_key_der,
                                                   sizeof(m_libspdm_mldsa_test_pub_key_der),
                                                   &mldsa_pub_key);
    if (!status) {
        libspdm_my_print("[Fail]");
        libspdm_mldsa_free(mldsa_priv_key);
        return false;
    } else {
        libspdm_my_print("[Pass]");
    }

    /* Verify ML-DSA */
    libspdm_my_print("\n- ML-DSA Verification using Public key from DER ... ");
    status = libspdm_mldsa_verify(mldsa_pub_key, context, sizeof(context),
                                  message, sizeof(message),
                                  signature, sig_size);
    if (!status) {
        libspdm_my_print("[Fail]");
        libspdm_mldsa_free(mldsa_priv_key);
        libspdm_mldsa_free(mldsa_pub_key);
        return false;
    } else {
        libspdm_my_print("[Pass]");
    }

    /* Retrieve ML-DSA Public key from X509 Certificate. */
    libspdm_my_print("\n- Retrieve ML-DSA Public key from X509 ... ");
    libspdm_mldsa_free(mldsa_pub_key);
    status = libspdm_mldsa_get_public_key_from_x509(m_libspdm_mldsa_test_cert_der,
                                                    sizeof(m_libspdm_mldsa_test_cert_der),
                                                    &mldsa_pub_key);
    if (!status) {
        libspdm_my_print("[Fail]");
        libspdm_mldsa_free(mldsa_priv_key);
        return false;
    } else {
        libspdm_my_print("[Pass]");
    }

    /* Verify ML-DSA */
    libspdm_my_print("\n- ML-DSA Verification using Public key from X509 ... ");
    status = libspdm_mldsa_verify(mldsa_pub_key, context, sizeof(context),
                                  message, sizeof(message),
                                  signature, sig_size);
    if (!status) {
        libspdm_my_print("[Fail]");
        libspdm_mldsa_free(mldsa_priv_key);
        libspdm_mldsa_free(mldsa_pub_key);
        return false;
    } else {
        libspdm_my_print("[Pass]\n");
    }

    libspdm_mldsa_free(mldsa_priv_key);
    libspdm_mldsa_free(mldsa_pub_key);

    return true;
}

#endif /* LIBSPDM_ML_DSA_SUPPORT */
